/etc/nginx/nginx.conf.content:
user www-data;
worker_processes auto;
pid /run/nginx.pid;

events {
    worker_connections 1024;
    multi_accept on;
}

http {
    sendfile on;
    tcp_nopush on;
    keepalive_timeout 65;
    server_tokens off;

    include /etc/nginx/mime.types;
    default_type application/octet-stream;

    access_log /var/log/nginx/access.log;
    error_log /var/log/nginx/error.log;

    gzip on;

    include /etc/nginx/conf.d/*.conf;
    include /etc/nginx/sites-enabled/*;
}

/etc/nginx/mime.types.content:
types {
    text/html html;
    text/css css;
    application/javascript js;
    application/json json;
}

/etc/nginx/sites-available/www.conf.content:
server {
    listen 80;
    server_name www.example.com example.com;
    root /var/www/example;
    index index.html;

    location / {
        try_files $uri $uri/ =404;
    }
}

/etc/nginx/sites-available/api.conf.content:
server {
    listen 80;
    server_name api.example.com;

    location /v1/ {
        proxy_pass http://127.0.0.1:3000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
    }
}

/etc/nginx/sites-available/legacy.conf.content:
server {
    listen 80;
    server_name legacy.example.com;
    root /var/www/legacy;
    index index.html;
}

/etc/nginx/sites-enabled/www.conf.content:
